import{_ as a,o,c as r,a3 as t}from"./chunks/framework.CjquFG0V.js";const l=JSON.parse('{"title":"47. Accrued Days Off","description":"","frontmatter":{"title":"47. Accrued Days Off","eba":"Health Allied & Managers Admin 2021-2025","topics":["preliminary"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/hours-of-work/47-accrued-days-off.md","filePath":"ebas/has-managers-admin/common-terms/hours-of-work/47-accrued-days-off.md"}'),s={name:"ebas/has-managers-admin/common-terms/hours-of-work/47-accrued-days-off.md"};function n(i,e,d,c,f,m){return o(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="_47-accrued-days-off" tabindex="-1">47. Accrued Days Off <a class="header-anchor" href="#_47-accrued-days-off" aria-label="Permalink to &quot;47. Accrued Days Off&quot;">​</a></h1><p><strong>47.1</strong> Entitlement to Accrued Days Off</p><p><strong>(a)</strong> Where the system of working provides for accrued days off, Employees will work an additional 0.4 hours per day, or 2 hours per week, to facilitate one accrued day off (ADO) after every 4 weeks of service.</p><p><strong>(b)</strong> An Employee may request, in writing to have their system of working reviewed by the Employer to determine whether the system of working provides for accrued days off.</p><p><strong>(c)</strong> An Employer will respond to the request, in writing, within 21 days of receipt.</p><p><strong>(d)</strong> If the Employee disputes the response of the Employer, the Employee may utilise <a href="/eba/ebas/has-managers-admin/common-terms/consultation-disputes/17-dispute-resolution-procedure.html">clause 17</a> – Dispute Resolution.</p><p><strong>(e)</strong> The maximum ADOs will be 13 in any calendar year, provided that one (1) ADO will be taken in conjunction with a period of annual leave, for which no additional payment is to be made.</p><p><strong>47.2</strong> Taking of Accrued Days Off</p><p><strong>(a)</strong> accrued days off are to be taken as single days on a rostered basis (i.e. 1 ADO in each 28-day cycle), as agreed between the Employer and Employee;</p><p><strong>(b)</strong> provided that the Employer and Employee may mutually agree to defer a rostered ADO for a maximum of one month, but only in exceptional circumstances.</p><p>Plain language terms: ADO, rostered day off, RDO.</p>',11)])])}const u=a(s,[["render",n]]);export{l as __pageData,u as default};
